import{_ as a,c as t,o,a2 as i}from"./chunks/framework.DDIT__tB.js";const b=JSON.parse('{"title":"📊 Model: Travel Planner","description":"","frontmatter":{},"headers":[],"relativePath":"examples/models/pcm/travel-planner.md","filePath":"examples/models/pcm/travel-planner.md"}'),r={name:"examples/models/pcm/travel-planner.md"};function s(l,e,n,d,c,h){return o(),t("div",null,e[0]||(e[0]=[i('<h1 id="📊-model-travel-planner" tabindex="-1">📊 Model: Travel Planner <a class="header-anchor" href="#📊-model-travel-planner" aria-label="Permalink to &quot;📊 Model: Travel Planner&quot;">​</a></h1><h2 id="🔗-link-to-original-paper-article" tabindex="-1">🔗 Link to Original Paper/Article <a class="header-anchor" href="#🔗-link-to-original-paper-article" aria-label="Permalink to &quot;🔗 Link to Original Paper/Article&quot;">​</a></h2><p><a href="https://doi.org/10.1109/ICSA.2019.00009" target="_blank" rel="noreferrer">View Source</a><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/pcm/TravelPlanner" target="_blank" rel="noreferrer">Open Example Model in Example Models Bundle</a></p><h2 id="📝-short-description" tabindex="-1">📝 Short Description <a class="header-anchor" href="#📝-short-description" aria-label="Permalink to &quot;📝 Short Description&quot;">​</a></h2><p>It models a user booking a flight with an travel planner application. Flights are queried using a travel agency that in turn communicates with the airline to determine flights. Using the flight information the user books an flight with their credit card details.</p><h2 id="🔤-abbreviations" tabindex="-1">🔤 Abbreviations <a class="header-anchor" href="#🔤-abbreviations" aria-label="Permalink to &quot;🔤 Abbreviations&quot;">​</a></h2><ul><li><code>ccd</code>: Credit Card Details, including Credit Card Number and CCV(Card Code Verification)</li></ul><h2 id="📖-extensive-description" tabindex="-1">📖 Extensive Description <a class="header-anchor" href="#📖-extensive-description" aria-label="Permalink to &quot;📖 Extensive Description&quot;">​</a></h2><p>This model consists of two different use cases:</p><p>The first use case <code>FlightPlanner</code> models a flight planner scheduling flights and adding them to an flight database. The saved flight can be accessed by anyone, denoted by them having every value of the <code>GrantedRoles</code> label.</p><p>The second use case <code>User</code> models a user booking a flight using their credit card. First, they store their credit card details in a local database using <code>store ccd</code> of the local <code>CreditCardDataDB</code>. The stored credit card details should only be accessible to the user. Then, the use the <code>FlightQuery</code> interface to find flights using a <code>query</code> and the <code>findFlights</code> method. The data <code>query</code> should be accessible to anyone, as it does not hold any confidential data. Using the stored credit card details and the found flights a flight is booked using the <code>FlightBooking</code> interface that provides the <code>book</code> method. Both the returned flights and credit card details are passed with their stored access permissions. Finally, the booking confirmation is returned to the user.</p><h2 id="🏷️-label-description" tabindex="-1">🏷️ Label Description <a class="header-anchor" href="#🏷️-label-description" aria-label="Permalink to &quot;🏷️ Label Description&quot;">​</a></h2><ul><li><h3 id="🗂️-data-labels" tabindex="-1">🗂️ Data Labels: <a class="header-anchor" href="#🗂️-data-labels" aria-label="Permalink to &quot;🗂️ Data Labels:&quot;">​</a></h3><ul><li><h3 id="grantedroles" tabindex="-1">GrantedRoles <a class="header-anchor" href="#grantedroles" aria-label="Permalink to &quot;GrantedRoles&quot;">​</a></h3><ul><li><strong>User</strong>: Users are allowed to access to the data</li><li><strong>Airline</strong>: The airline is allowed to access the data</li></ul></li></ul></li><li><h3 id="🏷️-node-labels" tabindex="-1">🏷️ Node Labels: <a class="header-anchor" href="#🏷️-node-labels" aria-label="Permalink to &quot;🏷️ Node Labels:&quot;">​</a></h3><ul><li><h3 id="assignedroles" tabindex="-1">AssignedRoles <a class="header-anchor" href="#assignedroles" aria-label="Permalink to &quot;AssignedRoles&quot;">​</a></h3><ul><li><strong>User</strong>: The current system belongs or is directly accessible to to the User</li><li><strong>Airline</strong>: The current system belongs or is directly accessible to to the airline</li></ul></li></ul></li></ul><h2 id="⚠️-constraints" tabindex="-1">⚠️ Constraints <a class="header-anchor" href="#⚠️-constraints" aria-label="Permalink to &quot;⚠️ Constraints&quot;">​</a></h2><h3 id="access-control-mechanism" tabindex="-1">Access Control Mechanism <a class="header-anchor" href="#access-control-mechanism" aria-label="Permalink to &quot;Access Control Mechanism&quot;">​</a></h3><p>Data that should only be accessed by a certain role, denoted by <code>GrantedRoles</code>, should only be accessible at nodes with the correct permissions. The permissions of a vertex are denoted by <code>AssignedRoles</code>. If a vertex does not have an <code>AssignedRole</code> or data does not have an <code>GrantedRole</code> the access is presumed to be allowed.</p><ul><li><code>data GrantedRoles.$grantedRoles neverFlows vertex AssignedRoles.$assignedRoles where present $grantedRoles present $assignedRoles empty intersection($grantedRoles,$assignedRoles)</code></li></ul><h2 id="🚨-violations" tabindex="-1">🚨 Violations <a class="header-anchor" href="#🚨-violations" aria-label="Permalink to &quot;🚨 Violations&quot;">​</a></h2><h3 id="access-control-mechanism-1" tabindex="-1">Access Control Mechanism <a class="header-anchor" href="#access-control-mechanism-1" aria-label="Permalink to &quot;Access Control Mechanism&quot;">​</a></h3><p>The vertices for the method/SEFF <code>book</code> and the contained vertex <code>return confirmation</code> violate the Access Control Rule as they receive the users credit card details without being cleared to hold them</p>',20)]))}const m=a(r,[["render",s]]);export{b as __pageData,m as default};
